const getDate=async()=>{try{const e=await fetch("https://timeapi.io/api/Time/current/zone?timeZone=Asia/Manila");if(!e.ok)return null;return(await e.json()).dateTime.slice(0,23)}catch(e){return null}},getTimeOffset=async()=>{const e=await getDate();return e?new Date(e).getTime()-Date.now():0},updateCountdown=(e,t)=>{const n=document.querySelector(".countdown"),o=document.querySelector(".countdown-finished"),a=e-new Date(Date.now()+t);if(a<=0)return n.classList.add("hidden"),void o.classList.remove("hidden");n.classList.remove("hidden"),o.classList.add("hidden");const d=6e4,i=36e5,s=24*i,r=Math.floor(a/s),c=Math.floor(a%s/i),u=Math.floor(a%i/d),l=Math.floor(a%d/1e3);document.getElementById("days").innerText=r,document.getElementById("hours").innerText=c,document.getElementById("minutes").innerText=u,document.getElementById("seconds").innerText=l},runWeddingTimer=e=>{const t=new Date(e).getTime();let n=0;setInterval(()=>{updateCountdown(t,n)},1e3);updateCountdown(t,n),getTimeOffset().then(e=>{n=e})};